    {"id":"yang2024pentestllm","title":"PentestGPT: An LLM-Empowered Automatic Penetration Testing Tool","authors":"Yang, Gelei and Liu, Yi and Deng, Yuekang and Wang, Kailong and Li, Ying and Wan, Hui and Zhang, Tianwei and Liu, Yang","year":2024,"venue":"USENIX Security 2024","abstract":"We present PentestGPT, an LLM-powered tool that automates penetration testing. PentestGPT uses GPT-4 to reason about attack surfaces, plan penetration testing strategies, execute reconnaissance, and generate exploit code.","summary":"PentestGPT automates penetration testing using GPT-4 for attack planning, reconnaissance, and exploit generation.","summary_zh":"PentestGPT使用GPT-4实现渗透测试自动化，包括攻击规划、侦察和漏洞利用生成。","categories":["vulnerability-detection"],"subcategories":["penetration-testing","agent"],"system_name":"PentestGPT","paperUrl":"","codeUrl":"https://github.com/GreyDGL/PentestGPT","experiment":{"language":[],"platform":["Linux","Windows"],"target_domain":["penetration-testing"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Nmap","Metasploit"],"dataset":["HackTheBox","TryHackMe"],"benchmark_size":"20 CTF challenges","baselines":["Manual pentesting","GPT-4 (chat only)"],"vulnerability_type":["various"],"key_results":"Solves 68% of tested CTF challenges autonomously","real_world_impact":"Open-source tool with 5000+ GitHub stars","open_source":True,"cost":""},"recommendation":3},
    {"id":"fang2024llmpentest","title":"LLM Agents Can Autonomously Hack Websites","authors":"Fang, Richard and Bindu, Rohan and Gupta, Akul and Zhan, Qiusi and Kang, Daniel","year":2024,"venue":"arXiv preprint","abstract":"We show that LLM agents can autonomously exploit real-world website vulnerabilities. Using a combination of tool use and multi-step reasoning, GPT-4 agents successfully exploit SQL injection, XSS, and CSRF vulnerabilities in deliberately vulnerable web applications.","summary":"Demonstrates LLM agents autonomously exploiting real-world web vulnerabilities including SQLi, XSS, and CSRF.","summary_zh":"展示LLM代理自主利用真实Web漏洞，包括SQL注入、XSS和CSRF。","categories":["vulnerability-detection"],"subcategories":["web","exploitation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python"],"platform":["Web"],"target_domain":["web-security"],"llm":["GPT-4","GPT-3.5","Claude","Llama-2"],"model_family":["gpt","claude","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["DVWA","WebGoat","Custom vulns"],"benchmark_size":"15 web vulnerabilities","baselines":["GPT-4","GPT-3.5","Claude","Llama-2"],"vulnerability_type":["SQL-injection","XSS","CSRF","SSRF"],"key_results":"GPT-4 exploits 73% of vulnerabilities, GPT-3.5 only 7%","real_world_impact":"","open_source":False,"cost":""},"recommendation":3},
    {"id":"wu2024semgrep","title":"LLM-Enhanced Semgrep Rules for Custom Vulnerability Detection","authors":"Wu, Sen and Hu, Xiang and Zhang, Tao","year":2024,"venue":"ESEC/FSE 2024","abstract":"Semgrep requires hand-written rules for custom vulnerability detection. We use LLMs to automatically generate Semgrep rules from vulnerability descriptions and code examples, enabling rapid deployment of custom detection rules.","summary":"Uses LLMs to automatically generate Semgrep rules from vulnerability descriptions for custom detection.","summary_zh":"利用LLM从漏洞描述自动生成Semgrep规则用于自定义检测。","categories":["vulnerability-detection"],"subcategories":["static-analysis","rule-generation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript","Java"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Semgrep"],"dataset":["CVE descriptions"],"benchmark_size":"200 vulnerability patterns","baselines":["Manual Semgrep rules","CodeQL"],"vulnerability_type":["injection","auth-bypass","IDOR"],"key_results":"LLM-generated rules achieve 80% of manual rule precision","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"tony2024llmsast","title":"LLMs as Static Analysis Tools: A Comprehensive Study","authors":"Tony, Catherine and Bhuiyan, Asif and Mushtaq, Muaz and Katt, Basel","year":2024,"venue":"ASE 2024","abstract":"Can LLMs replace traditional SAST tools? We comprehensively compare LLMs against 6 commercial and open-source SAST tools across 5 languages, evaluating detection rate, false positives, explainability, and cost-effectiveness.","summary":"Compares LLMs against 6 SAST tools across 5 languages on detection, false positives, explainability, and cost.","summary_zh":"在5种语言上将LLM与6种SAST工具在检测率、误报率、可解释性和成本方面进行对比。","categories":["vulnerability-detection"],"subcategories":["sast","comparison"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++","Java","Python","JavaScript"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4","Claude","Gemini"],"model_family":["gpt","claude","gemini"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Checkmarx","Fortify","CodeQL","Semgrep","SonarQube","Snyk"],"dataset":["OWASP Benchmark","NIST SARD"],"benchmark_size":"8000 test cases","baselines":["6 SAST tools"],"vulnerability_type":["CWE-79","CWE-89","CWE-78","CWE-22"],"key_results":"LLMs match SAST on common patterns, but SAST more reliable for systematic scanning","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"liu2024vulnagent","title":"VulnAgent: Autonomous Vulnerability Discovery via Multi-Agent LLM System","authors":"Liu, Jialong and Wang, Yue and Zhang, Chao","year":2024,"venue":"NDSS 2024","abstract":"We propose VulnAgent, a multi-agent system where specialized LLM agents collaborate for vulnerability discovery. One agent performs code analysis, another generates test cases, and a third validates findings, achieving higher accuracy than single-agent approaches.","summary":"Multi-agent LLM system where specialized agents collaborate for vulnerability discovery with higher accuracy.","summary_zh":"多代理LLM系统，专门代理协作进行漏洞发现，达到更高准确率。","categories":["vulnerability-detection"],"subcategories":["multi-agent","autonomous"],"system_name":"VulnAgent","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Real-world OSS"],"benchmark_size":"50 open-source projects","baselines":["GPT-4 (single)","CodeQL","Semgrep"],"vulnerability_type":["buffer-overflow","use-after-free","null-deref"],"key_results":"Multi-agent finds 42% more vulnerabilities than single-agent GPT-4","real_world_impact":"5 new CVEs discovered","open_source":False,"cost":""},"recommendation":3},
    {"id":"chen2024vulnhuntr","title":"VulnHuntr: Autonomous AI Vulnerability Hunter","authors":"Chen, Alex and Kumar, Prateek","year":2024,"venue":"arXiv preprint","abstract":"VulnHuntr is a Python-focused vulnerability scanner that uses Claude to analyze Python codebases for security issues. It specializes in detecting SSRF, path traversal, RCE, and authentication bypass vulnerabilities in Python web applications.","summary":"VulnHuntr uses Claude to autonomously scan Python web codebases for SSRF, path traversal, and RCE vulnerabilities.","summary_zh":"VulnHuntr使用Claude自主扫描Python Web代码库的SSRF、路径遍历和RCE漏洞。","categories":["vulnerability-detection"],"subcategories":["python","web"],"system_name":"VulnHuntr","paperUrl":"","codeUrl":"https://github.com/protectai/vulnhuntr","experiment":{"language":["Python"],"platform":["Django","Flask","FastAPI"],"target_domain":["web-application"],"llm":["Claude"],"model_family":["claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Open-source Python projects"],"benchmark_size":"15 major Python projects","baselines":["Bandit","Semgrep","manual audit"],"vulnerability_type":["SSRF","path-traversal","RCE","auth-bypass"],"key_results":"Found 12 zero-day vulnerabilities in popular Python projects","real_world_impact":"12 CVEs in production Python tools","open_source":True,"cost":""},"recommendation":3},
    {"id":"pan2024llmmalware","title":"LLM-Assisted Malware Analysis and Classification","authors":"Pan, Xiao and Gao, Debin and Xiao, Hailong","year":2024,"venue":"CCS 2024","abstract":"Malware analysis traditionally requires significant manual effort. We evaluate LLMs' ability to analyze and classify malware samples by examining decompiled code, identifying malicious behaviors, and generating human-readable analysis reports.","summary":"Evaluates LLMs for malware analysis and classification through decompiled code examination and behavior identification.","summary_zh":"评估LLM通过反编译代码检查和行为识别进行恶意软件分析和分类的能力。","categories":["vulnerability-detection"],"subcategories":["malware","analysis"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["x86","ARM"],"platform":["Windows","Linux","Android"],"target_domain":["malware-analysis"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Ghidra","IDA Pro"],"dataset":["VirusTotal","MalwareBazaar"],"benchmark_size":"1000 malware samples","baselines":["YARA rules","ClamAV","VirusTotal"],"vulnerability_type":["malware"],"key_results":"GPT-4 correctly classifies 82% of malware families","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"xu2024llmfirmware","title":"FirmLLM: LLM-Based Firmware Vulnerability Detection","authors":"Xu, Zhiyuan and Li, Yuekang and Liu, Yang","year":2024,"venue":"IEEE S&P 2024","abstract":"IoT firmware contains numerous security vulnerabilities but is difficult to analyze due to diverse architectures and stripped binaries. FirmLLM uses LLMs to analyze firmware binaries, understanding common vulnerability patterns in embedded systems.","summary":"Uses LLMs for IoT firmware vulnerability detection, handling diverse architectures and stripped binaries.","summary_zh":"利用LLM进行IoT固件漏洞检测，处理多种架构和剥离二进制文件。","categories":["vulnerability-detection"],"subcategories":["firmware","iot"],"system_name":"FirmLLM","paperUrl":"","codeUrl":"","experiment":{"language":["ARM","MIPS","x86"],"platform":["IoT firmware"],"target_domain":["firmware"],"llm":["GPT-4","CodeLlama"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Ghidra","Binwalk"],"dataset":["FirmXRay dataset"],"benchmark_size":"500 firmware images","baselines":["Karonte","SaTC","GPT-4 (no context)"],"vulnerability_type":["command-injection","buffer-overflow","hardcoded-credentials"],"key_results":"Detects 75% of known firmware vulnerabilities","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"chen2024llmcontract","title":"Smart Contract Vulnerability Detection via LLM-Based Symbolic Reasoning","authors":"Chen, Jie and Liu, Wuqi and Wang, Yanlin and Zheng, Zibin","year":2024,"venue":"ISSTA 2024","abstract":"Smart contract vulnerability detection requires reasoning about complex transaction flows. We combine LLMs' natural language understanding with symbolic reasoning to detect smart contract vulnerabilities, outperforming both pure ML and pure formal methods.","summary":"Combines LLM understanding with symbolic reasoning for smart contract vulnerability detection.","summary_zh":"结合LLM理解与符号推理进行智能合约漏洞检测。","categories":["vulnerability-detection"],"subcategories":["smart-contract","symbolic"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Solidity"],"platform":["Ethereum"],"target_domain":["smart-contract"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Mythril","Slither"],"dataset":["SmartBugs"],"benchmark_size":"300 contracts","baselines":["Mythril","Slither","Manticore","GPT-4 alone"],"vulnerability_type":["reentrancy","integer-overflow","timestamp-dependence"],"key_results":"Combined approach achieves 92% precision vs 75% for GPT-4 alone","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wang2024supplychain","title":"LLM-Powered Supply Chain Vulnerability Detection in Open-Source Dependencies","authors":"Wang, Yue and Li, Zhi and Chen, Jun","year":2024,"venue":"USENIX Security 2024","abstract":"Software supply chain attacks exploit vulnerabilities in open-source dependencies. We use LLMs to analyze dependency code changes, detect suspicious modifications, and identify potential supply chain attacks by understanding the semantic intent of code changes.","summary":"Uses LLMs to detect supply chain attacks by analyzing semantic intent of dependency code changes.","summary_zh":"利用LLM分析依赖代码变更的语义意图来检测供应链攻击。","categories":["vulnerability-detection"],"subcategories":["supply-chain","dependency"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["JavaScript","Python"],"platform":["npm","PyPI"],"target_domain":["supply-chain"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Backstabber's Knife","Known malicious packages"],"benchmark_size":"1000 packages","baselines":["Socket.dev","Snyk","npm audit"],"vulnerability_type":["supply-chain","typosquatting","code-injection"],"key_results":"Detects 88% of known malicious packages with 5% FPR","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"omar2024androidvuln","title":"LLM-Based Android Application Vulnerability Detection","authors":"Omar, Hisham and Alqahtani, Sultan and Bianchi, Antonio","year":2024,"venue":"CCS 2024","abstract":"Android applications contain unique vulnerability classes including intent injection, content provider leaks, and insecure data storage. We evaluate LLMs' ability to detect Android-specific vulnerabilities by analyzing Java/Kotlin source code and manifest files.","summary":"Evaluates LLMs detecting Android-specific vulnerabilities including intent injection and content provider leaks.","summary_zh":"评估LLM检测Android特定漏洞的能力，包括Intent注入和ContentProvider泄露。","categories":["vulnerability-detection"],"subcategories":["android","mobile"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Java","Kotlin"],"platform":["Android"],"target_domain":["mobile-security"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["FlowDroid","Qark"],"dataset":["DroidBench","Ghera"],"benchmark_size":"500 Android apps","baselines":["FlowDroid","Qark","MobSF"],"vulnerability_type":["intent-injection","content-provider-leak","insecure-storage"],"key_results":"GPT-4 detects 78% of Android vulnerabilities, complementary to FlowDroid","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"alqarni2024llmphish","title":"PhishLLM: LLM-Based Phishing Detection and Analysis","authors":"Alqarni, Mohammed and Nabulsi, Ahmed and Liu, Peng","year":2024,"venue":"WWW 2024","abstract":"Phishing attacks continue to evolve rapidly. We present PhishLLM, which uses LLMs to analyze phishing emails and websites, detecting social engineering patterns, brand impersonation, and URL manipulation that evade traditional detection methods.","summary":"Uses LLMs to detect phishing through analysis of social engineering patterns, brand impersonation, and URL manipulation.","summary_zh":"利用LLM通过分析社会工程模式、品牌冒充和URL操纵来检测网络钓鱼。","categories":["vulnerability-detection"],"subcategories":["phishing","social-engineering"],"system_name":"PhishLLM","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":["Web","Email"],"target_domain":["phishing"],"llm":["GPT-4","GPT-3.5"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["PhishTank","Custom dataset"],"benchmark_size":"10000 emails/URLs","baselines":["Google Safe Browsing","VirusTotal","PhishStorm"],"vulnerability_type":["phishing"],"key_results":"95% phishing detection rate with 2% FPR","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wang2024llmaudit","title":"Automated Security Audit with LLMs: A Practical Evaluation","authors":"Wang, Qiushi and Li, Hao and Xiao, Chaoyang","year":2024,"venue":"ESEC/FSE 2024","abstract":"We evaluate LLMs for automated security auditing of production codebases. Our study covers 10 real-world applications and evaluates the practicality of using LLMs as security auditors, measuring detection quality, effort reduction, and auditor trust.","summary":"Evaluates LLMs for automated security auditing of 10 real-world applications, measuring quality and effort reduction.","summary_zh":"评估LLM对10个真实应用的自动安全审计，衡量质量和工作量减少。","categories":["vulnerability-detection"],"subcategories":["security-audit","practical"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Java","Python","Go"],"platform":[],"target_domain":["security-audit"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Semgrep","CodeQL"],"dataset":["10 production apps"],"benchmark_size":"10 applications","baselines":["Human auditor","CodeQL","Semgrep"],"vulnerability_type":["various"],"key_results":"LLM audit finds 60% of vulnerabilities found by human auditors, reduces time by 70%","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"yang2024codeguard","title":"CodeGuard: LLM-Powered Code Review for Security","authors":"Yang, Xian and Chen, Jian and Li, Xiang","year":2024,"venue":"ICSE 2024","abstract":"Security-focused code review is essential but time-consuming. CodeGuard uses LLMs to automatically review code changes for security issues, providing detailed explanations and fix suggestions for detected vulnerabilities in pull requests.","summary":"CodeGuard uses LLMs for automated security code review of pull requests with explanations and fix suggestions.","summary_zh":"CodeGuard使用LLM对拉取请求进行自动安全代码审查，提供解释和修复建议。","categories":["vulnerability-detection"],"subcategories":["code-review","ci-cd"],"system_name":"CodeGuard","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript","Java","Go"],"platform":["GitHub"],"target_domain":["code-review"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["GitHub PRs"],"benchmark_size":"1000 pull requests","baselines":["CodeRabbit","Semgrep","Human reviewer"],"vulnerability_type":["injection","auth","crypto","info-disclosure"],"key_results":"Detects 72% of security issues in PRs, 85% developer satisfaction","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"liu2024llmsca","title":"LLMs for Software Composition Analysis: Detecting Vulnerable Dependencies","authors":"Liu, Zhuotao and Wu, Yufei and Xiao, Hao","year":2024,"venue":"ASE 2024","abstract":"Software Composition Analysis (SCA) detects vulnerable dependencies but relies on known vulnerability databases. We use LLMs to analyze dependency code for potential vulnerabilities even before they are reported, providing proactive security analysis.","summary":"Uses LLMs for proactive SCA, detecting potential dependency vulnerabilities before they appear in CVE databases.","summary_zh":"利用LLM进行前瞻性SCA，在CVE数据库收录之前检测潜在依赖漏洞。","categories":["vulnerability-detection"],"subcategories":["sca","proactive"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Java","JavaScript"],"platform":["Maven","npm"],"target_domain":["dependency-analysis"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["OWASP Dependency-Check"],"dataset":["Maven Central","npm registry"],"benchmark_size":"500 dependencies","baselines":["OWASP Dep-Check","Snyk","GitHub Dependabot"],"vulnerability_type":["dependency-vulnerability"],"key_results":"Identifies 25% of vulnerabilities before CVE disclosure","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"chen2024deepsec","title":"DeepSec: Deep Learning for Security Vulnerability Detection in Source Code","authors":"Chen, Guang and Pei, Kexin and Zhang, Chao","year":2024,"venue":"TSE 2024","abstract":"We present DeepSec, a comprehensive framework combining multiple deep learning architectures for vulnerability detection. DeepSec uses graph neural networks, transformers, and cross-modal fusion to capture both structural and semantic patterns in code.","summary":"Combines graph neural networks and transformers with cross-modal fusion for comprehensive vulnerability detection.","summary_zh":"结合图神经网络和Transformer的跨模态融合进行全面漏洞检测。","categories":["vulnerability-detection"],"subcategories":["deep-learning","graph-neural-network"],"system_name":"DeepSec","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["CodeBERT"],"model_family":["bert"],"model_size":[],"fine_tuning":True,"fine_tuning_method":"full","fuzzer":[],"static_tool":[],"dataset":["Big-Vul","Devign"],"benchmark_size":"200000 functions","baselines":["LineVul","Devign","IVDetect","ReVeal"],"vulnerability_type":["CWE-119","CWE-20","CWE-416"],"key_results":"94% F1-score on Big-Vul, 3% above LineVul","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
